{
    "level": "A2–B2",
    "intro": "In this topic, we have collected the <strong>most common mistakes</strong> when using the passive voice and practical tips on how to avoid them. Learning from mistakes is the best way not to repeat them!",
    "rules": [
        {
            "label": "Be + V3",
            "color": "emerald",
            "text": "Don't forget <strong>the verb be</strong> and <strong>V3 (Past Participle)</strong>:",
            "example": "The letter is written. ✅ (не: The letter written. ❌)"
        },
        {
            "label": "V3 ≠ V2",
            "color": "rose",
            "text": "Use <strong>V3</strong>, not V2:",
            "example": "The window was broken. ✅ (не: was broke. ❌)"
        },
        {
            "label": "Without do/does",
            "color": "blue",
            "text": "In <strong>questions do not use do/does/did</strong>:",
            "example": "Is the letter written? ✅ (не: Does the letter is written? ❌)"
        }
    ]
}

{
    "title": "1. Errors with the verb BE",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Omission of the verb be.",
            "wrong": "The letter written yesterday.",
            "right": "✅ The letter was written yesterday."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Incorrect form of be (is/are).",
            "wrong": "The letters is sent every day.",
            "right": "✅ The letters are sent every day."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Incorrect form of be (was/were).",
            "wrong": "The windows was broken.",
            "right": "✅ The windows were broken."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Skip been in Perfect.",
            "wrong": "The work has done.",
            "right": "✅ The work has been done."
        }
    ]
}

{
    "title": "2. Errors with the Past Participle (V3)",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Using V1 (infinitive) instead of V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using V2 (past simple) instead of V3.",
            "wrong": "The window was broke.",
            "right": "✅ The window was broken."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Confusion of irregular verbs.",
            "wrong": "The book was writed by him.",
            "right": "✅ The book was written by him."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Using -ing instead of V3.",
            "wrong": "The letter is writing now.",
            "right": "✅ The letter is being written now."
        }
    ]
}

{
    "title": "3. Errors in questions",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Using do/does/did in questions.",
            "wrong": "Does the letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Incorrect word order.",
            "wrong": "The letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Error in wh-questions.",
            "wrong": "Where the book was found?",
            "right": "✅ Where was the book found?"
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect short answer.",
            "wrong": "Was the work done? — Yes, it done.",
            "right": "✅ Was the work done? — Yes, it was."
        }
    ]
}

{
    "title": "4. Errors in objections",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Omission of not or incorrect location.",
            "wrong": "The letter is not write.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using don't/doesn't.",
            "wrong": "The work doesn't finished.",
            "right": "✅ The work isn't finished."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Incorrect form of not.",
            "wrong": "The letter is no written.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Error in Perfect.",
            "wrong": "The work hasn't done.",
            "right": "✅ The work hasn't been done."
        }
    ]
}

{
    "title": "5. Errors with by and with",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Using with for executor.",
            "wrong": "The book was written with Shakespeare.",
            "right": "✅ The book was written by Shakespeare."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using by for a tool.",
            "wrong": "The letter was written by a pen.",
            "right": "✅ The letter was written with a pen."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Redundant by + agent.",
            "wrong": "My car was stolen by someone.",
            "right": "✅ My car was stolen."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect location by.",
            "wrong": "By the team the report was prepared.",
            "right": "✅ The report was prepared by the team."
        }
    ]
}

{
    "title": "6. Correct examples of use",
    "sections": [
        {
            "label": "Present Simple Passive",
            "color": "emerald",
            "description": "<strong>am/is/are + V3</strong>:",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "English is spoken in many countries."
                },
                {
                    "en": "The office is cleaned every day.",
                    "ua": "The office is cleaned every day."
                },
                {
                    "en": "Cars are made in Germany.",
                    "ua": "Cars are made in Germany."
                }
            ]
        },
        {
            "label": "Past Simple Passive",
            "color": "blue",
            "description": "<strong>was/were + V3</strong>:",
            "examples": [
                {
                    "en": "The letter was sent yesterday.",
                    "ua": "The letter was sent yesterday."
                },
                {
                    "en": "The house was built in 1990.",
                    "ua": "The house was built in 1990."
                },
                {
                    "en": "The windows were broken during the storm.",
                    "ua": "The windows were broken during the storm."
                }
            ]
        },
        {
            "label": "Present Perfect Passive",
            "color": "amber",
            "description": "<strong>has/have been + V3</strong>:",
            "examples": [
                {
                    "en": "The work has been completed.",
                    "ua": "The work has been completed."
                },
                {
                    "en": "All tickets have been sold.",
                    "ua": "All tickets have been sold."
                },
                {
                    "en": "The report has been submitted.",
                    "ua": "The report has been submitted."
                }
            ]
        },
        {
            "label": "Modal Passive",
            "color": "rose",
            "description": "<strong>modal + be + V3</strong>:",
            "examples": [
                {
                    "en": "The task must be done today.",
                    "ua": "The task must be done today."
                },
                {
                    "en": "This problem can be solved.",
                    "ua": "This problem can be solved."
                },
                {
                    "en": "The report should be checked carefully.",
                    "ua": "The report should be checked carefully."
                }
            ]
        }
    ]
}

{
    "title": "7. The correct conversion of Active → Passive",
    "intro": "Step-by-step transformation of active sentences into passive ones:",
    "rows": [
        {
            "en": "Active: Tom writes letters.",
            "ua": "Active: Tom writes letters.",
            "note": "→ Passive: Letters are written by Tom."
        },
        {
            "en": "Active: She cleaned the room.",
            "ua": "Active: She cleaned the room.",
            "note": "→ Passive: The room was cleaned."
        },
        {
            "en": "Active: They have finished the project.",
            "ua": "Active: They have finished the project.",
            "note": "→ Passive: The project has been finished."
        },
        {
            "en": "Active: Someone must do this work.",
            "ua": "Active: Someone must do this work.",
            "note": "→ Passive: This work must be done."
        }
    ],
    "warning": "📌 Object of active sentence → Subject of passive. Verb → be + V3."
}

{
    "title": "8. Checklist for checking liabilities",
    "intro": "Check your sentence against these points:",
    "items": [
        {
            "label": "✓ 1",
            "title": "Is there a BE verb?",
            "subtitle": "am/is/are/was/were/been/being"
        },
        {
            "label": "✓ 2",
            "title": "Is the correct form of BE in time?",
            "subtitle": "Present: is/are; Past: was/were"
        },
        {
            "label": "✓ 3",
            "title": "Is V3 (Past Participle) used?",
            "subtitle": "written, broken, done, made"
        },
        {
            "label": "✓ 4",
            "title": "Is the V3 form correct?",
            "subtitle": "broken (не broke), written (не writed)"
        },
        {
            "label": "✓ 5",
            "title": "Are there no do/does/did in questions?",
            "subtitle": "Is it done? (не: Does it is done?)"
        },
        {
            "label": "✓ 6",
            "title": "Is by/with correct?",
            "subtitle": "by + agent; with + instrument"
        }
    ]
}
